{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a constrained optimization task involving graph embedding (topological mapping) onto a grid. To solve it, one must first model the adjacency constraints and then find an optimal layout that minimizes the footprint of the colored cells.",
  "helpers": [
    {
      "label": "graph_modeling_and_constraint_definition",
      "instructions": "Represent the city map as a graph where nodes are colored regions and edges represent color-adjacency. Define the constraints for the 50x50 grid: each region must be a contiguous set of cells, and adjacent regions in the graph must share at least one grid edge (4-connectivity) or corner (8-connectivity) depending on the specific topological rule, while ensuring no two non-adjacent regions touch if that violates the map's topology."
    },
    {
      "label": "layout_optimization_and_empty_space_maximization",
      "instructions": "Using the graph model, execute a packing algorithm (such as simulated annealing, constraint programming, or a greedy growth algorithm) to place the regions on the 50x50 grid. The objective function is to minimize the total number of cells occupied by colored regions (the footprint) to maximize the number of empty cells E, while strictly adhering to the adjacency and connectivity constraints defined in the first step."
    }
  ],
  "synthesis_brief": "Combine the valid topological layout produced by the optimization step with the original map's adjacency requirements to ensure all constraints are met. Calculate the final number of empty cells E and provide the grid configuration as the solution."
}
```

